bodyGraphql.query:
query ListUsers {
  users(role: ADMIN, active: true) {
    id
    name
    email
    role
    active
  }
}

query GetUser($id: ID!) {
  user(id: $id) {
    id
    name
    email
    role
  }
}

mutation CreateUser($name: String!, $role: Role) {
  createUser(name: $name, role: $role) {
    id
    name
    email
    role
    active
  }
}

query IntrospectionQuery {
  __schema {
    queryType { name }
    mutationType { name }
    types {
      kind
      name
    }
  }
}
